// 當前頻率計算
Stochastic(Length, RSVt, Kt, rsv, k, _d);

// 指定頻率跨週期計算
xf_Stochastic(頻率, Length, RSVt, Kt, rsv, k, _d);

input: Length(9), RSVt(3), Kt(3);
variable: rsv(0), k(0), _d(0);
SetTotalBar(maxlist(Length, 6) * 3);
Stochastic(Length, RSVt, Kt, rsv, k, _d);
Plot1(k, "K");
Plot2(_d, "D");

// 黃金交叉：K 由下往上穿越 D
condition1 = k cross above _d;

// 死亡交叉：K 由上往下跌破 D
condition2 = k cross below _d;

// 低檔黃金交叉更可靠
if condition1 and k < 20 then ret = 1;
